import{_ as t}from"./chunks/via-layout-example.yiytcZ4t.js";import{_ as e,o,c as i,ag as r}from"./chunks/framework.DmiIFzQJ.js";const n="/docs/layout-options-all-light.png",l="/docs/layout-options-all-dark.png",s="/docs/layout-options-choice-preview-light.png",d="/docs/layout-options-choice-preview-dark.png",v=JSON.parse('{"title":"VIA & Vial Format","description":"","frontmatter":{},"headers":[],"relativePath":"via-and-metadata.md","filePath":"via-and-metadata.md"}'),c={name:"via-and-metadata.md"};function h(p,a,u,m,y,g){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="via-vial-format" tabindex="-1">VIA &amp; Vial Format <a class="header-anchor" href="#via-vial-format" aria-label="Permalink to &quot;VIA &amp; Vial Format&quot;">​</a></h1><h2 id="via-format" tabindex="-1">What is VIA? <a class="header-anchor" href="#via-format" aria-label="Permalink to &quot;What is VIA? {#via-format}&quot;">​</a></h2><p><a href="https://www.caniusevia.com/" target="_blank" rel="noreferrer">VIA</a> and <a href="https://get.vial.today/" target="_blank" rel="noreferrer">Vial</a> are keyboard configuration tools used to remap keycodes on a running keyboard without reflashing firmware. They rely on a keyboard definition file that describes the physical layout alongside switch matrix wiring.</p><p>VIA format is a JSON file that wraps KLE layout data with additional metadata:</p><ul><li>Keyboard name</li><li>Vendor and product IDs</li><li>Matrix configuration (number of rows and columns)</li><li>Key matrix coordinates in labels</li></ul><p>The key labels use a special format that maps physical key positions to switch matrix coordinates. For example, a key labeled <code>0,1</code> is in row 0, column 1 of the switch matrix. To learn more, see the <a href="https://www.caniusevia.com/docs/layouts" target="_blank" rel="noreferrer">VIA specification</a>.</p><p><strong>When do you need VIA format?</strong></p><ul><li>You are designing a keyboard that will use VIA or Vial for key remapping</li><li>You want to use the <a href="./pcb-generator.html">PCB Generator</a>, which reads matrix coordinates from key labels</li><li>You are working from an existing VIA keyboard definition and want to edit the layout visually</li></ul><p>If you only need a visual layout for documentation or plate generation, you do not need VIA format.</p><p><img src="'+t+'" alt="VIA layout example showing matrix coordinates on keycaps" class="docs-screenshot"></p><h2 id="matrix-coordinates" tabindex="-1">Matrix Coordinates <a class="header-anchor" href="#matrix-coordinates" aria-label="Permalink to &quot;Matrix Coordinates {#matrix-coordinates}&quot;">​</a></h2><p>Matrix coordinates identify where each physical switch connects in the keyboard&#39;s electrical matrix. Each coordinate is written as <code>row,col</code> (e.g., <code>0,0</code>, <code>0,1</code>, <code>1,0</code>).</p><p>The easiest way to assign coordinates is <strong>Extra Tools → Add Switch Matrix Coordinates</strong>. This tool lets you annotate your layout automatically or draw rows and columns manually. See <a href="./layout-editor.html#add-switch-matrix-coordinates">Add Switch Matrix Coordinates</a> for detailed instructions.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Automatic annotations may not produce correct results for certain keyboard layouts, particularly <strong>ergonomic layouts with significant column splay</strong>. Manual correction may be required for complex designs. See <a href="https://github.com/adamws/kle-ng/issues/51" target="_blank" rel="noreferrer">issue #51</a> for details.</p></div><p>If you already have matrix coordinates (from a QMK or VIA import), they will appear in the top-left label position of each key.</p><h2 id="importing-via" tabindex="-1">Importing VIA Layouts <a class="header-anchor" href="#importing-via" aria-label="Permalink to &quot;Importing VIA Layouts {#importing-via}&quot;">​</a></h2><p>To import a VIA layout file (e.g., from the <a href="https://github.com/the-via/keyboards" target="_blank" rel="noreferrer">VIA keyboards repository</a>):</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li>Click the <strong>Import</strong> button in the toolbar</li><li>Select <strong>From File</strong> and choose a VIA JSON file (or use <strong>From URL</strong> with a direct link)</li><li>The layout will be displayed and VIA metadata will appear in the <strong>VIA Metadata</strong> field of the <strong>Keyboard Metadata</strong> panel</li></ol><h3 id="format-conversion" tabindex="-1">Format Conversion <a class="header-anchor" href="#format-conversion" aria-label="Permalink to &quot;Format Conversion&quot;">​</a></h3><p>On import, kle-ng converts the VIA format to KLE format and preserves the VIA-specific metadata in a <code>_kleng_via_data</code> field within the KLE JSON, maintaining full KLE compatibility.</p><h2 id="alternative-layouts-preview" tabindex="-1">Alternative Layouts Preview <a class="header-anchor" href="#alternative-layouts-preview" aria-label="Permalink to &quot;Alternative Layouts Preview {#alternative-layouts-preview}&quot;">​</a></h2><p>VIA keyboard definitions can declare <strong>alternative key layouts</strong> — different physical arrangements of the same keyboard. For example, a keyboard might support both a full-width backspace and a split backspace, or both ISO Enter and ANSI Enter. Each alternative is a separate layout option, and they are identified by special labels in VIA format.</p><p>When you load a layout containing alternative layout options, a <strong>Layout Options toolbar</strong> automatically appears below the canvas. This toolbar lets you preview each layout variant without editing.</p><h3 id="layout-options-toolbar" tabindex="-1">Layout Options Toolbar <a class="header-anchor" href="#layout-options-toolbar" aria-label="Permalink to &quot;Layout Options Toolbar&quot;">​</a></h3><p>The toolbar displays:</p><ul><li>An <strong>&quot;all&quot; button</strong> — shows all keys including alternatives. This is the normal, fully editable view.</li><li><strong>Choice buttons</strong> — one button for each layout variant, displayed as a fraction (e.g., <code>1 ⁄ 2</code> for choice 1 out of 2 variants). Hover over a button to see the VIA-provided name (e.g., &quot;Split Backspace&quot;) if available, or a generic label like &quot;Option 0 · Choice 1&quot;.</li></ul><img src="'+n+'" class="docs-screenshot light-only" alt="Layout Options toolbar showing all and choice buttons below the canvas"><img src="'+l+'" class="docs-screenshot dark-only" alt="Layout Options toolbar showing all and choice buttons below the canvas"><h3 id="preview-mode" tabindex="-1">Preview Mode <a class="header-anchor" href="#preview-mode" aria-label="Permalink to &quot;Preview Mode&quot;">​</a></h3><p>Click any choice button to enter <strong>preview mode</strong>, which displays only the keys that belong to that layout variant, with their physical positions on the assembled keyboard.</p><p>In preview mode:</p><ul><li>The layout is <strong>read-only</strong> — the Key Properties panel is disabled, mutation buttons do not work, and canvas gestures (drag, delete, paste) are blocked.</li><li>An inline hint appears next to the toolbar reading: <em>&quot;Layout preview mode (readonly) — switch to all to edit&quot;</em>.</li><li>You can preview multiple option groups simultaneously by clicking different choice buttons for each group.</li><li>Clicking <strong>&quot;all&quot;</strong> returns to the normal editable view, leaving your layout unchanged.</li></ul><img src="'+s+'" class="docs-screenshot light-only" alt="Canvas in preview mode showing only the selected layout variant"><img src="'+d+'" class="docs-screenshot dark-only" alt="Canvas in preview mode showing only the selected layout variant"><p>The toolbar is hidden when your layout does not contain alternative layout options.</p><h2 id="exporting-via" tabindex="-1">Exporting to VIA Format <a class="header-anchor" href="#exporting-via" aria-label="Permalink to &quot;Exporting to VIA Format {#exporting-via}&quot;">​</a></h2><p>Layouts that contain VIA metadata can be exported back to VIA format:</p><h3 id="steps-1" tabindex="-1">Steps <a class="header-anchor" href="#steps-1" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li>Click the <strong>Export</strong> button in the toolbar</li><li>Select <strong>Download VIA JSON</strong></li></ol><h3 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;Availability&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The <strong>Download VIA JSON</strong> option is only available when VIA metadata is present in the layout.</p></div><h2 id="editing-via-metadata" tabindex="-1">Editing VIA Metadata <a class="header-anchor" href="#editing-via-metadata" aria-label="Permalink to &quot;Editing VIA Metadata {#editing-via-metadata}&quot;">​</a></h2><p>The VIA metadata is stored as JSON and can be edited directly in the <strong>VIA Metadata</strong> field. The editor validates your input in real-time — invalid JSON is highlighted with an error indicator.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>kle-ng does <strong>not</strong> validate the <em>content</em> of the JSON. It is your responsibility to maintain VIA format conventions as defined in the <a href="https://www.caniusevia.com/docs/specification" target="_blank" rel="noreferrer">VIA specification</a>.</p></div><p><strong>Tips:</strong></p><ul><li>Clearing the field removes all VIA metadata from the layout</li><li>VIA metadata is preserved when exporting to KLE format (stored in the <code>_kleng_via_data</code> field)</li><li>You can manually edit the metadata to customize keyboard name, vendor ID, product ID, and other fields</li></ul>',47)])])}const w=e(c,[["render",h]]);export{v as __pageData,w as default};
